using System.Collections;
using QuickCode.Demo.Infrastructure.Web.Extensions;
using Serilog;

namespace QuickCode.Demo.Infrastructure.Web.Helpers;

public static class EnvironmentHelper
{
    private const string QuickCodeEnvPrefix = "QUICKCODE_";

    public static void LoadEnvFile(string? envFilePath = null)
    {
        try
        {
            if (string.IsNullOrEmpty(envFilePath))
            {
                var currentDirectory = Directory.GetCurrentDirectory();
                var defaultEnvPath = Path.Combine(currentDirectory, ".env");
                
                if (!File.Exists(defaultEnvPath))
                {
                    var parentEnvPath = Path.Combine(Directory.GetParent(currentDirectory)?.FullName ?? currentDirectory, ".env");
                    if (File.Exists(parentEnvPath))
                    {
                        envFilePath = parentEnvPath;
                    }
                    else
                    {
                        envFilePath = defaultEnvPath;
                    }
                }
                else
                {
                    envFilePath = defaultEnvPath;
                }
            }

            if (File.Exists(envFilePath))
            {
                DotNetEnv.Env.Load(envFilePath);
                Log.Information("Loaded .env file from: {EnvFilePath}", envFilePath);
            }
            else
            {
                Log.Debug(".env file not found at: {EnvFilePath}", envFilePath);
            }
        }
        catch (Exception ex)
        {
            Log.Warning(ex, "Failed to load .env file: {Message}", ex.Message);
        }
    }

    public static void UpdateConfigurationFromEnv(this IConfiguration configuration)
    {
        LoadEnvFile();

        foreach (DictionaryEntry entry in Environment.GetEnvironmentVariables())
        {
            if (entry.Key is not string envKey)
            {
                continue;
            }

            var envValue = entry.Value?.ToString();
            if (string.IsNullOrWhiteSpace(envValue))
            {
                continue;
            }

            // Gateway JWT key material (private/public) and the internal token key are read
            // directly from environment variables by the signer/validator and must never be
            // mirrored into IConfiguration/appsettings.
            configuration.TrySetConfigValueIfKeyExists($"QuickcodeClients:{envKey.GetPascalCase()}", envValue);
            configuration.TrySetConfigValueIfKeyExists($"ConnectionStrings:{envKey.GetPascalCase()}", envValue);
        }
    }

    private static void TrySetConfigValueIfKeyExists(this IConfiguration configuration, string key, string value)
    {
        if (configuration[key] == null)
        {
            return;
        }

        configuration[key] = value;
        Log.Information("Config {Key} updated from environment variable", key);
    }
}
